import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { randomUUID } from 'crypto';

const s3 = new S3Client({
  region: process.env.AWS_REGION,
  credentials: {
    accessKeyId: process.env.AWS_ACCESS_KEY_ID!,
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY!,
  },
});

const BUCKET = process.env.S3_BUCKET!;

// Upload a file
async function uploadFile(file: Buffer, mimeType: string, folder: string) {
  const key = `${folder}/${randomUUID()}.${getExtension(mimeType)}`;

  await s3.send(new PutObjectCommand({
    Bucket: BUCKET,
    Key: key,
    Body: file,
    ContentType: mimeType,
  }));

  return `https://${BUCKET}.s3.amazonaws.com/${key}`;
}

// Generate a presigned URL (client uploads directly to S3)
async function getUploadUrl(key: string, mimeType: string) {
  const command = new PutObjectCommand({
    Bucket: BUCKET,
    Key: key,
    ContentType: mimeType,
  });
  return getSignedUrl(s3, command, { expiresIn: 600 }); // 10 minutes
}

import sharp from 'sharp';

async function processAvatar(inputBuffer: Buffer) {
  // Generate multiple sizes for responsive images
  const sizes = [64, 128, 256, 512];

  const results = await Promise.all(
    sizes.map(async (size) => {
      const buffer = await sharp(inputBuffer)
        .resize(size, size, { fit: 'cover', position: 'centre' })
        .webp({ quality: 80 })
        .toBuffer();

      return { size, buffer, filename: `avatar-${size}.webp` };
    })
  );

  return results;
}

// Express route for image upload
router.post('/upload/avatar', upload.single('avatar'), async (req, res) => {
  if (!req.file) return res.status(400).json({ error: 'No file provided' });

  const variants = await processAvatar(req.file.buffer);

  // Upload all sizes to S3
  const urls = await Promise.all(
    variants.map(v => uploadFile(v.buffer, 'image/webp', 'avatars'))
  );

  res.json({ data: { avatars: urls } });
});
